UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('a38c0e93-75a6-4dba-820f-1e589d775a38'::uuid, 'La digestion peut être ralentie ou déséquilibrée, et les probiotiques contribuent à l''harmonie de la flore intestinale.'),('d69ec5f5-3237-4a70-993c-dce9b12cfcfd'::uuid, 'Les ISRS peuvent impacter le métabolisme, et la vitamine D3 aide à réguler les fonctions osseuses et immunitaires essentielles à l''organisme.'),('f5d854e6-cebe-4bd8-9dc3-484240afdff6'::uuid, 'Les ISRS peuvent impacter le métabolisme, et la vitamine D3 aide à réguler les fonctions osseuses et immunitaires essentielles à l''organisme.'),('06bf711c-bd0b-4a12-8761-697f42fba684'::uuid, 'Les ISRS peuvent impacter le métabolisme, et la vitamine D3 aide à réguler les fonctions osseuses et immunitaires essentielles à l''organisme.'),('9fdcf25d-257e-4860-beaa-476e0df487f0'::uuid, 'Les macrolides peuvent déséquilibrer la flore intestinale, et les probiotiques Lactibiane aident à restaurer une bonne digestion.'),('630e6111-1f3b-43af-a1c6-b49cc989255a'::uuid, 'Le traitement antibiotique peut affaiblir l''organisme, et la vitamine C participe au renforcement de vos défenses immunitaires.'),('d06a7abb-2da1-4d30-8adb-f338743d405b'::uuid, 'Les macrolides peuvent occasionner une irritation de la gorge, et le spray à la propolis apaise la muqueuse et réduit l''inflammation locale.'),('3ab25071-6bfb-41de-a52a-bdf95376049e'::uuid, 'Les traitements métaboliques peuvent influencer l''équilibre nutritionnel, et la vitamine D3 est essentielle au maintien d''une fonction osseuse et immunitaire saine.'),('9022138f-6c19-494f-8c44-3dac286f5a11'::uuid, 'Le stress et la fatigue sont des symptômes fréquents avec ces pathologies, et le magnésium B6 aide à rétablir l''équilibre nerveux et musculaire.'),('4ca1a55a-6c5b-4461-a3d8-5e0c492e3852'::uuid, 'Un traitement par mydriatiques n''impacte pas directement le statut vitaminique, la vitamine D3 est fondamentale pour la santé osseuse et immunitaire générale.'),('791a9ccd-c21d-4f6c-ae00-e984183a63c9'::uuid, 'Bien que non directement lié, le magnésium B6 est crucial pour la fonction nerveuse et musculaire, réduisant la fatigue globale.'),('546fb911-09da-4dbe-99a2-2f08e5f1a2af'::uuid, 'Les probiotiques renforcent la flore intestinale, un pilier de l''immunité, ce qui est bénéfique pour l''organisme de manière générale.'),('1bdf492c-a4cf-4edc-9f95-719b5c7c6296'::uuid, 'La vitamine D3 joue un rôle clé dans la fonction musculaire et immunitaire, contribuant au maintien de la vitalité de l''organisme.'),('f38b8986-5305-490b-ae5b-d1e0c50e8481'::uuid, 'Les myorelaxants peuvent accentuer la fatigue musculaire, et le magnésium B6 est essentiel pour réduire la contraction et la tension neuromusculaire.'),('a6d05603-c00a-49fe-a6a4-a45c1244d2a2'::uuid, 'Le stress et la fatigue peuvent perturber le système nerveux, le magnésium B6 aide à réguler les fonctions neurologiques.'),('9d0bd23d-2db5-46f2-b76f-7b1887f1a637'::uuid, 'Un déséquilibre de la flore intestinale peut affecter l''immunité, les probiotiques aident à restaurer cette microflore pour une meilleure défense.'),('84ca2664-58cd-4cbf-a766-ea64bb139e36'::uuid, 'Des douleurs musculaires peuvent survenir, l''Arnigel agit sur l''inflammation locale pour apaiser les tensions musculaires.'),('6dc1e7f6-28c8-4021-8fc0-21e25a788999'::uuid, 'Des douleurs musculaires peuvent survenir, l''Arnigel agit sur l''inflammation locale pour apaiser les tensions musculaires.'),('2f000312-162d-4722-9d19-428a05880a8a'::uuid, 'Des douleurs musculaires peuvent survenir, l''Arnigel agit sur l''inflammation locale pour apaiser les tensions musculaires.'),('f5e6b356-890e-495f-b2b2-8882ebc47bd6'::uuid, 'Les crampes et tensions musculaires indiquent souvent un déficit en magnésium, ce complément aide à la fonction musculaire normale.'),('8d51feb0-5e10-45ba-9d13-3a588c9b4bf2'::uuid, 'Les tensions musculaires entraînent une gêne, la chaleur locale favorise la relaxation des fibres pour un relâchement rapide.'),('53c1f69c-1366-4b22-87c0-f88a2f4ba342'::uuid, 'Des douleurs musculaires peuvent survenir, l''Arnigel agit sur l''inflammation locale pour apaiser les tensions musculaires.'),('dc3fb530-d59c-4bda-bbca-26c1865ecc50'::uuid, 'Les crampes et tensions musculaires indiquent souvent un déficit en magnésium, ce complément aide à la fonction musculaire normale.'),('cc7971c2-b96e-4b14-abe9-83e8cc347b49'::uuid, 'Les tensions musculaires entraînent une gêne, la chaleur locale favorise la relaxation des fibres pour un relâchement rapide.'),('8afa8258-162d-45b4-bb43-cd2083b78d49'::uuid, 'Les antibiotiques peuvent perturber la flore intestinale, les probiotiques réensemencent les bonnes bactéries pour un équilibre digestif.'),('93c34154-bb33-4266-95d3-93dcea1b6aab'::uuid, 'Un affaiblissement immunitaire peut rendre plus vulnérable, la vitamine C contribue à renforcer les défenses de l''organisme.'),('ac8f73e5-c074-457c-9093-5d2b32c0a429'::uuid, 'L''inflammation de la gorge cause des irritations, le spray à la propolis aide à calmer cette irritation pour un soulagement rapide.'),('93a04f84-d27e-4a76-96f1-73ff5c0ec65b'::uuid, 'Les antibiotiques peuvent perturber la flore intestinale, les probiotiques réensemencent les bonnes bactéries pour un équilibre digestif.'),('7c223a0b-de3b-4fc4-adf1-c5e9837a690b'::uuid, 'Un affaiblissement immunitaire peut rendre plus vulnérable, la vitamine C contribue à renforcer les défenses de l''organisme.'),('525c6fc6-6307-4fec-a02c-1159dbe84df7'::uuid, 'L''inflammation de la gorge cause des irritations, le spray à la propolis aide à calmer cette irritation pour un soulagement rapide.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;